cat > /tmp/binlog-reader/BinlogReader/Program.cs << 'CSHARP'
using Microsoft.Build.Logging.StructuredLogger;
using System;
using System.Collections.Generic;
using System.Linq;

var binlogPath = args[0];
var build = BinaryLog.ReadBuild(binlogPath);

// Collect all errors
var errors = new List<(string Project, string Code, string Message, string File, int Line)>();
var warnings = new List<(string Project, string Code, string Message, string File, int Line)>();

build.VisitAllChildren<Error>(e =>
{
    var project = "";
    var parent = e.Parent;
    while (parent != null)
    {
        if (parent is Project p) { project = p.Name; break; }
        parent = (parent as TreeNode)?.Parent;
    }
    errors.Add((project, e.Code ?? "", e.Text ?? "", e.File ?? "", e.LineNumber));
});

build.VisitAllChildren<Warning>(w =>
{
    var project = "";
    var parent = w.Parent;
    while (parent != null)
    {
        if (parent is Project p) { project = p.Name; break; }
        parent = (parent as TreeNode)?.Parent;
    }
    warnings.Add((project, w.Code ?? "", w.Text ?? "", w.File ?? "", w.LineNumber));
});

Console.WriteLine("=== BUILD ERRORS ===");
Console.WriteLine($"Total errors: {errors.Count}");
Console.WriteLine();

var byProject = errors.GroupBy(e => e.Project).OrderBy(g => g.Key);
foreach (var group in byProject)
{
    Console.WriteLine($"--- Project: {group.Key} ---");
    foreach (var e in group)
    {
        Console.WriteLine($"  [{e.Code}] {e.File}({e.Line}): {e.Message}");
    }
    Console.WriteLine();
}

// Also look at project build results
Console.WriteLine("=== PROJECT BUILD RESULTS ===");
build.VisitAllChildren<Project>(p =>
{
    if (p.FindChild<Error>() != null || p.Succeeded == false)
    {
        Console.WriteLine($"  FAILED: {p.Name} (Succeeded={p.Succeeded})");
    }
});
Console.WriteLine();

// Print relevant warnings if any
if (warnings.Any(w => w.Code.StartsWith("CS") || w.Code.StartsWith("MSB") || w.Code.StartsWith("NU")))
{
    Console.WriteLine("=== RELEVANT WARNINGS ===");
    foreach (var w in warnings.Where(w => w.Code.StartsWith("CS") || w.Code.StartsWith("MSB") || w.Code.StartsWith("NU")))
    {
        Console.WriteLine($"  [{w.Code}] {w.Project} - {w.File}({w.Line}): {w.Message}");
    }
}
