cat > /tmp/binlog-reader/BinlogReader/Program.cs << 'CSHARP'
using Microsoft.Build.Logging.StructuredLogger;
using System;
using System.Collections.Generic;
using System.Linq;

var binlogPath = args[0];
var build = BinaryLog.ReadBuild(binlogPath);

// Look for project references and package references from items
Console.WriteLine("=== PROJECT STRUCTURE & DEPENDENCIES ===");
var seen = new HashSet<string>();
build.VisitAllChildren<Project>(p =>
{
    if (!seen.Add(p.Name + "|" + p.SourceFilePath)) return;
    Console.WriteLine($"\nProject: {p.Name} ({p.SourceFilePath})");

    // Find AddItem for PackageReference and ProjectReference
    p.VisitAllChildren<NamedNode>(n =>
    {
        if (n.Name == "PackageReference" || n.Name == "ProjectReference")
        {
            Console.WriteLine($"  Item: {n.Name}");
            if (n is Folder f)
            {
                foreach (var child in f.Children)
                    Console.WriteLine($"    - {child}");
            }
        }
    });

    // Look for AddItem nodes
    p.VisitAllChildren<AddItem>(ai =>
    {
        if (ai.Name == "PackageReference" || ai.Name == "ProjectReference")
        {
            Console.WriteLine($"  AddItem: {ai.Name}");
            foreach (var child in ai.Children)
                Console.WriteLine($"    - {child}");
        }
    });
});

// Look for NuGet restore messages
Console.WriteLine("\n=== NUGET RESTORE MESSAGES ===");
build.VisitAllChildren<Message>(m =>
{
    if (m.Text != null && (m.Text.Contains("Newtonsoft") || m.Text.Contains("PackageReference")))
    {
        if (m.Text.Length < 500)
            Console.WriteLine($"  {m.Text}");
    }
});

// Check for MSB3277 or other assembly reference warnings
Console.WriteLine("\n=== ALL WARNINGS ===");
build.VisitAllChildren<Warning>(w =>
{
    Console.WriteLine($"  [{w.Code}] {w.Text}");
});
