cat > /tmp/binlog-reader/BinlogReader/Program.cs << 'CSHARP'
using Microsoft.Build.Logging.StructuredLogger;
using System;
using System.Collections.Generic;
using System.Linq;

var binlogPath = args[0];
var build = BinaryLog.ReadBuild(binlogPath);

// Deep dive: look at all Item nodes within projects
var seen = new HashSet<string>();
build.VisitAllChildren<Project>(p =>
{
    var key = p.Name + "|" + p.SourceFilePath + "|" + p.GetHashCode();
    if (!seen.Add(key)) return;

    // Look at every child recursively for anything with "Reference" in name
    Console.WriteLine($"\n=== Project: {p.Name} ({p.SourceFilePath}) ===");

    // Get Items folder
    p.VisitAllChildren<Item>(item =>
    {
        var parentName = (item.Parent as NamedNode)?.Name ?? "";
        if (parentName.Contains("Reference") || parentName.Contains("Package"))
        {
            Console.WriteLine($"  [{parentName}] {item.Text}");
        }
    });
});

// Also look at properties for the project
Console.WriteLine("\n\n=== DETAILED ERROR CONTEXT ===");
build.VisitAllChildren<Error>(e =>
{
    Console.WriteLine($"\nError: [{e.Code}] {e.Text}");
    Console.WriteLine($"  File: {e.File}:{e.LineNumber}");
    Console.WriteLine($"  Subcategory: {e.Subcategory}");

    // Walk up to find containing project/target
    var parent = e.Parent;
    var depth = 0;
    while (parent != null && depth < 10)
    {
        if (parent is Target t) Console.WriteLine($"  Target: {t.Name}");
        if (parent is Project p) { Console.WriteLine($"  Project: {p.Name} ({p.SourceFilePath})"); break; }
        parent = (parent as TreeNode)?.Parent;
        depth++;
    }
});

// Dump the raw tree structure for Services.csproj failures
Console.WriteLine("\n\n=== SERVICES.CSPROJ ITEMS DETAILS ===");
build.VisitAllChildren<Project>(p =>
{
    if (p.Name != "Services.csproj") return;

    // Get all Folders (which represent item groups)
    p.VisitAllChildren<Folder>(f =>
    {
        if (f.Name == "Items" || f.Name == "PackageReference" || f.Name == "ProjectReference" || f.Name == "Reference")
        {
            Console.WriteLine($"  Folder: {f.Name} (children: {f.Children.Count})");
            foreach (var child in f.Children.Take(20))
            {
                Console.WriteLine($"    - {child} ({child.GetType().Name})");
                if (child is TreeNode tn)
                {
                    foreach (var gc in tn.Children.Take(5))
                        Console.WriteLine($"      . {gc}");
                }
            }
        }
    });
});
