using Microsoft.Build.Logging.StructuredLogger;
using System;
using System.Collections.Generic;
using System.IO;
using System.IO.Compression;
using System.Linq;

var binlogPath = args[0];
var build = BinaryLog.ReadBuild(binlogPath);

// Check if Api.csproj build encountered any errors (cascade from Services.csproj)
Console.WriteLine("=== CHECKING FOR CASCADE FAILURES ===");

// Look at all targets per project that failed
build.VisitAllChildren<Project>(p =>
{
    var failedTargets = new List<string>();
    p.VisitAllChildren<Target>(t =>
    {
        var hasError = false;
        t.VisitAllChildren<Error>(_ => hasError = true);
        if (hasError) failedTargets.Add(t.Name);
    });

    if (failedTargets.Any())
    {
        Console.WriteLine($"\n{p.Name} ({p.SourceFilePath}) - Failed targets: {string.Join(", ", failedTargets)}");

        // Show all errors in this project
        p.VisitAllChildren<Error>(e =>
        {
            Console.WriteLine($"  Error [{e.Code}]: {e.Text}");
        });
    }
});

// Check for MSB4181 or other build-engine-level errors indicating cascading failures
Console.WriteLine("\n=== MSB ERRORS (build engine errors) ===");
build.VisitAllChildren<Error>(e =>
{
    if (e.Code != null && e.Code.StartsWith("MSB"))
    {
        Console.WriteLine($"  [{e.Code}] {e.Text}");
    }
});

// Check if Api.csproj had any build issues at all
Console.WriteLine("\n=== API.CSPROJ BUILD STATUS ===");
build.VisitAllChildren<Project>(p =>
{
    if (p.Name == "Api.csproj")
    {
        var anyError = false;
        p.VisitAllChildren<Error>(_ => anyError = true);
        Console.WriteLine($"  Api.csproj instance ({p.GetHashCode()}) - Has errors: {anyError}");
    }
});

// Check for "project build failed" messages
Console.WriteLine("\n=== BUILD MESSAGES ABOUT FAILURES ===");
build.VisitAllChildren<Message>(m =>
{
    if (m.Text != null && (m.Text.Contains("failed") || m.Text.Contains("skipped") || m.Text.Contains("not build")))
    {
        if (m.Text.Length < 300)
            Console.WriteLine($"  {m.Text}");
    }
});

// Show the dependency chain
Console.WriteLine("\n=== SOLUTION STRUCTURE ===");
Console.WriteLine("Core.csproj -> (no project refs)");
Console.WriteLine("Services.csproj -> Core.csproj");
Console.WriteLine("Api.csproj -> Services.csproj, Core.csproj");
Console.WriteLine();
Console.WriteLine("Services.csproj uses Newtonsoft.Json (JObject) but has NO PackageReference for it");
CSHARP

